Method.Source:
/// <summary>
/// EventHandler for the Inserting event of the <c>VendTable</c> table.
/// </summary>
/// <param name="_sender">The common record representing the current instance of <c>VendTable</c>.</param>
/// <param name="_e">DataEventArgs object containing event data.</param>
[DataEventHandler(tableStr(VendTable), DataEventType::Inserting)]
public static void VendTable_onInserting(Common _sender, DataEventArgs _e)
{
    VendTable vendTable = _sender as VendTable;

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        vendTable.AccountNum = vendTable.ETGSPAINGenerateVendAccount();
    }
}
